I agree that passing VideoClips is a pain.
Here is my experimentation workaround:


```
class Ucf101(UCF101):

    def __init__(self, root, annotation_path, frames_per_clip, step_between_clips=1,
                 fold=1, train=True, spatial_transform=None, audio_transform=None):

        super().__init__(root, frames_per_clip, step_between_clips)
        self.audio_transform = audio_transform
        self.spatial_transform = spatial_transform

    def __getitem__(self, idx):
        video, audio, info, video_idx = self.video_clips.get_clip(idx)
        label = self.samples[video_idx][1]

        if self.audio_transform:
            audio = self.audio_transform(audio)
        if self.spatial_transform:
            video = self.spatial_transform(video)

        return video, audio, label, video_idx

    def set_spatial_transform(self, transform):
        self.spatial_transform = transform
    
    def set_audio_transform(self, transform):
        self.audio_transform = transform
```

