Move this script into a function.  Eventually this will have to become a beast on its own that will have to reside within `/resolwe_bio/tools/` 

Perhaps something along the lines of

```python
import os
import utils
import json


def expression_to_storage(rc_input, rc_output):
    
    if not (rc_input and os.path.isfile(rc_input)):
        raise ValueError("Specify rc_input")

    def isfloat(value):
        """Check if value is float."""
        try:
            float(value)
            return True
        except ValueError:
            return False

    with utils.gzopen(rc_input) as f:
        # Split lines by tabs
        # Ignore lines without a number in second column
        # Build a dictionary of gene-expression pairs
        exp = {
            "genes": {
                gene_exp[0]: float(gene_exp[1])
                for gene_exp in (l.split("\t") for l in f)
                if len(gene_exp) == 2 and isfloat(gene_exp[1])
            }
        }

    if rc_output:
        with open(file=rc_output, mode="wt") as f:
            json.dump(exp, f)
    
    return rc_output
```

